reproducibility_commands.compare_paired_dirs_inline_python:
python -c "import os, hashlib
def sha256_file(p):
    h = hashlib.sha256()
    with open(p, 'rb') as f:
        for chunk in iter(lambda: f.read(65536), b''): h.update(chunk)
    return h.hexdigest().upper()
def tree(root):
    m = {}
    for dp, _, fns in os.walk(root):
        for fn in fns:
            full = os.path.join(dp, fn)
            rel = os.path.relpath(full, root).replace(os.sep, '/')
            m[rel] = sha256_file(full)
    return m
for d in ['admin','src','widget','config']:
    o, i = tree(f'E:/{d}'), tree(f'E:/GT-KB/{d}')
    print(d, 'matched=', sum(1 for k in o if k in i and o[k]==i[k]))
"
